import type { WithRef } from '@andes/common';
import type { FunctionComponent, SyntheticEvent } from 'react';

type DeprecatedColors = 'green' | 'red';

type ActionConfig = {
  onClick?: (
    event: SyntheticEvent<HTMLAnchorElement | HTMLButtonElement>,
  ) => void;
  position?: 'bottom' | 'right';
  text?: string;
};

type SnackbarProps = WithRef<HTMLDivElement> & {
  /**
   * Configuration element for the Snackbar action.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/snackbar#props | Documentation}
   */
  action?: ActionConfig;

  /**
   * Custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/snackbar#props | Documentation}
   */
  className?: string;

  /**
   * Color of the Snackbar, to show different states.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/snackbar#props | Documentation}
   */
  color?: DeprecatedColors | 'negative' | 'positive';

  /**
   * Time in ms that the snackbar will be displayed, after those ms, the snackbar will be automatically hidden.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/snackbar#props | Documentation}
   */
  delay?: number;

  /**
   * Inner Snackbar message.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/snackbar#props | Documentation}
   */
  message: string;

  /**
   * Callback executed once the snackbar is closed.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/snackbar#props | Documentation}
   */
  onClose?: () => void;

  /**
   * Callback executed once the snackbar is open.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/snackbar#props | Documentation}
   */
  onOpen?: () => void;

  /**
   * Determines whether the snackbar is visible or not.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/snackbar#props | Documentation}
   */
  show?: boolean;
};

/**
 * Snackbar used to quickly and concisely communicate the status of an event.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/snackbar | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/791b82-snackbar/b/26f535 | UI Specs}
 * @example
 * import { Snackbar } from '@andes/snackbar';
 *
 * const MyComponent = () => (
 *  <Snackbar
 *    message="Mensaje de Snackbar"
 *    color="green"
 *    action={{ text: "Salida" }}
 *    show
 *    delay={3000}
 *  />
 * );
 */
export const Snackbar: FunctionComponent<SnackbarProps>;

export type ActionConfigType = ActionConfig;
